def topological_sort(graph):
    # Track the in-degree of each node
    in_degree = {node: 0 for node in graph}

    # Calculate in-degrees
    for nodes in graph.values():
        for dependency in nodes:
            in_degree[dependency] += 1

    # Initialize queue with all nodes that have no dependencies (indegree == 0)
    from collections import deque
    queue = deque([node for node, degree in in_degree.items() if degree == 0])

    topological_ordering = []

    while queue:
        current_node = queue.popleft()
        topological_ordering.append(current_node)

        # Decrease the in-degree of each neighbor by removing the dependency on the current node
        for dependent_node in graph[current_node]:
            in_degree[dependent_node] -= 1
            if in_degree[dependent_node] == 0:
                queue.append(dependent_node)

    # If there are nodes remaining with non-zero in-degrees, a cycle exists.
    if len(topological_ordering) != len(in_degree):
        raise ValueError("Graph contains one or more cycles. Topological ordering is not possible.")

    return topological_ordering
